1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Quote — base premiums and edge cases
6	  it("empty item list yields premium of 5 G (processing fee only)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it.todo("single sword with no modifiers yields 100 G + 5 G fee = 105 G");
14	  it.todo("single amulet base premium 60 G + fee = 65 G");
15	  it.todo("single staff base premium 80 G + fee = 85 G");
16	  it.todo("single potion base premium 40 G + fee = 45 G");
17	  it.todo("two swords sum to 200 G + fee = 205 G");
18	
19	  // Components and blocks
20	  it.todo("single component (rune) base premium 25 G + fee = 30 G");
21	  it.todo("2 runes → 50 G base + fee = 55 G");
22	  it.todo("3 alike runes → 60 G block discount + fee = 65 G");
23	  it.todo("4 runes → 100 G (no block) + fee = 105 G");
24	  it.todo("7 runes → 175 G base premium + fee = 180 G");
25	  it.todo("2 runes + 1 moonstone → 75 G + fee = 80 G (different types, no block)");
26	  it.todo("3 runes + 3 moonstones → 120 G + fee = 125 G (two separate blocks)");
27	
28	  // Item-specific modifiers
29	  it.todo("cursed sword adds 50% surcharge on item base (100 + 50) + fee = 155 G");
30	  it.todo("sword with enchantment exactly 5 adds 30% high-enchantment surcharge");
31	  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
32	  it.todo("cursed sword with enchantment 5 applies both surcharges");
33	
34	  // Policy-wide modifiers
35	  it.todo("customer with exactly 2 years gets 20% loyalty discount");
36	  it.todo("first insurance adds 10% on policy base premium");
37	  it.todo("second contract gets 15% follow-up discount");
38	  it.todo("modifier scope: cursed sword + plain amulet → policy base 160 G, +50 G cursed, +fee");
39	
40	  // Rounding
41	  it.todo("premium calculation rounds up in MHPCO's favor");
42	
43	  // Integration examples from spec
44	  it.todo("newcomer with cursed sword → 165 G");
45	  it.todo("long-standing customer's second contract with cursed enchanted sword → 160 G");
46	
47	  // Claims — basic
48	  it.todo("standard sword damage 500 G → payout 400 G (full minus 100 G deductible)");
49	  it.todo("rune damage 200 G → payout 100 G");
50	  it.todo("damage to item with enchantment >=8 reimbursed at 50%");
51	  it.todo("damage to dragon material item fully reimbursed");
52	  it.todo("dragon material sword enchantment 9 damage 1000 → payout 400 (50% wins)");
53	  it.todo("dragon material sword enchantment 5 damage 800 → payout 700");
54	  it.todo("steel sword enchantment 9 damage 1000 → payout 400");
55	  it.todo("multiple damages each get own deductible");
56	  it.todo("policy cap = 2× insurance sum, exhaustion across multiple claims");
57	  it.todo("payout rounds down in MHPCO's favor");
58	
59	  // Validation / error handling
60	  it.todo("unknown item type in quote → non-zero exit, error to stderr");
61	  it.todo("claim referencing item not in policy → non-zero exit");
62	  it.todo("claim with negative damage amount → non-zero exit");
63	  it.todo("more damage entries of a type than policy covers → non-zero exit");
64	});
